commands.examples:
-- Membuat database sederhana
CREATE DATABASE toko_online;

-- Dengan opsi lengkap
CREATE DATABASE toko_online
  WITH OWNER = admin
  ENCODING = 'UTF8'
  LC_COLLATE = 'id_ID.UTF-8'
  CONNECTION LIMIT = 100;

-- Dari template
CREATE DATABASE dev_db TEMPLATE prod_db;

DROP DATABASE toko_online;
DROP DATABASE IF EXISTS test_db;
DROP DATABASE busy_db WITH (FORCE);

ALTER DATABASE toko_online RENAME TO ecommerce;
ALTER DATABASE ecommerce OWNER TO admin;
ALTER DATABASE ecommerce SET timezone = 'Asia/Jakarta';
ALTER DATABASE ecommerce SET work_mem = '256MB';

CREATE SCHEMA inventory;
CREATE SCHEMA IF NOT EXISTS sales AUTHORIZATION admin;

-- Menggunakan schema
SET search_path TO inventory, public;
CREATE TABLE inventory.products (id SERIAL PRIMARY KEY, name TEXT);
SELECT * FROM inventory.products;
